const products = [{name: 'Apple', price: 100}, {name: 'Banana', price: 50}];
const selected = products.map(p => ({name: p.name, price: p.price}));
console.log(selected);

List<Map> products = List.of(
  Map.of("name", "Apple", "price", 100),
  Map.of("name", "Banana", "price", 50)
);
List<Map> selected = products.stream()
    .map(p -> Map.of("name", p.get("name"), "price", p.get("price")))
    .collect(Collectors.toList());
